const body = $input.item.json;
const headers = $input.item.headers || {};

const alertTitle = body.title || body.alert || body.message || 'Alert';
const severity = body.severity || body.level || 'info';

let emoji = '🔔';
let color = 3447003;

if (severity === 'critical' || severity === 'error' || severity === 'high') {
  emoji = '🚨';
  color = 15158332;
} else if (severity === 'warning' || severity === 'warn') {
  emoji = '⚠️';
  color = 15105570;
} else if (severity === 'success' || severity === 'low') {
  emoji = '✅';
  color = 3066993;
}

let message = `${emoji} *${alertTitle}*\n\n`;

for (const [key, value] of Object.entries(body)) {
  if (['title', 'alert', 'message', 'severity', 'level'].includes(key)) continue;
  if (typeof value === 'object') continue;
  message += `*${key}:* \`${value}\`\n`;
}

return [{ json: { message, color } }];
